import { useEffect, useState } from 'react';
import API from '../api/axios';

function AdminPage() {
  const [members, setMembers] = useState([]);
  const [posts, setPosts] = useState([]);
  const [messages, setMessages] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  const loadAdminData = async () => {
    setError('');
    setLoading(true);

    try {
      const [usersRes, postsRes, messagesRes] = await Promise.all([
        API.get('/admin/users'),
        API.get('/admin/posts'),
        API.get('/admin/messages'),
      ]);

      setMembers(usersRes.data);
      setPosts(postsRes.data);
      setMessages(messagesRes.data);
    } catch (err) {
      setError(err?.response?.data?.message || 'Unable to load admin dashboard data.');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadAdminData();
  }, []);

  const handleToggleStatus = async (memberId) => {
    try {
      const res = await API.put(`/admin/users/${memberId}/status`);
      setMembers((prev) => prev.map((member) => (member._id === memberId ? res.data.user : member)));
    } catch (err) {
      setError(err?.response?.data?.message || 'Unable to update member status.');
    }
  };

  const handleRemovePost = async (postId) => {
    try {
      await API.put(`/admin/posts/${postId}/remove`);
      setPosts((prev) => prev.map((post) => (post._id === postId ? { ...post, status: 'removed' } : post)));
    } catch (err) {
      setError(err?.response?.data?.message || 'Unable to remove post.');
    }
  };

  return (
    <main className="admin-page">
      <section className="admin-header">
        <h2>Admin Dashboard</h2>
        <p>Review all members, posts, and incoming contact messages from one place.</p>
      </section>

      {loading ? (
        <p>Loading admin data...</p>
      ) : error ? (
        <p className="error-text">{error}</p>
      ) : (
        <>
          <section className="admin-section">
            <h3>Members</h3>
            {members.length === 0 ? (
              <p>No members found.</p>
            ) : (
              <table>
                <thead>
                  <tr>
                    <th>Name</th>
                    <th>Email</th>
                    <th>Role</th>
                    <th>Status</th>
                    <th>Action</th>
                  </tr>
                </thead>
                <tbody>
                  {members.map((member) => (
                    <tr key={member._id}>
                      <td>{member.name}</td>
                      <td>{member.email}</td>
                      <td>{member.role}</td>
                      <td>{member.status}</td>
                      <td>
                        <button onClick={() => handleToggleStatus(member._id)}>
                          {member.status === 'active' ? 'Deactivate' : 'Activate'}
                        </button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            )}
          </section>

          <section className="admin-section">
            <h3>Posts</h3>
            {posts.length === 0 ? (
              <p>No posts found.</p>
            ) : (
              <table>
                <thead>
                  <tr>
                    <th>Title</th>
                    <th>Author</th>
                    <th>Status</th>
                    <th>Created</th>
                    <th>Action</th>
                  </tr>
                </thead>
                <tbody>
                  {posts.map((post) => (
                    <tr key={post._id}>
                      <td>{post.title}</td>
                      <td>{post.author?.name || 'Unknown'}</td>
                      <td>{post.status || 'active'}</td>
                      <td>{new Date(post.createdAt).toLocaleString()}</td>
                      <td>
                        <button onClick={() => handleRemovePost(post._id)} disabled={post.status === 'removed'}>
                          {post.status === 'removed' ? 'Removed' : 'Mark Removed'}
                        </button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            )}
          </section>

          <section className="admin-section">
            <h3>Contact Messages</h3>
            {messages.length === 0 ? (
              <p>No contact messages have been sent yet.</p>
            ) : (
              <table>
                <thead>
                  <tr>
                    <th>Name</th>
                    <th>Email</th>
                    <th>Message</th>
                    <th>Received</th>
                  </tr>
                </thead>
                <tbody>
                  {messages.map((message) => (
                    <tr key={message._id}>
                      <td>{message.name}</td>
                      <td>{message.email}</td>
                      <td>{message.message}</td>
                      <td>{new Date(message.createdAt).toLocaleString()}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            )}
          </section>
        </>
      )}
    </main>
  );
}

export default AdminPage;
